Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string filename, wordToFind, line;
    int count = 0;

    // Ask the user for the filename and the word to find
    std::cout << "Enter the name of the file: ";
    std::cin >> filename;
    std::cout << "Enter the word to find: ";
    std::cin >> wordToFind;

    // Open the file
    std::ifstream inputFile(filename);

    // Check if the file is open, if not, display an error message and exit
    if (!inputFile.is_open()) {
        std::cerr << "Error opening the file." << std::endl;
        return 1;
    }

    // Read the file line by line
    while (getline(inputFile, line)) {
        // Count the number of occurrences of the word in the current line
        size_t pos = 0;
        while ((pos = line.find(wordToFind, pos))!= std::string::npos) {
            ++count;
            pos += wordToFind.length();
        }
    }

    // Close the file
    inputFile.close();

    // Display the result
    std::cout << "The word '" << wordToFind << "' occurs " << count << " times in the file." << std::endl;

    return 0;
}
```

