#include <stdio.h>

void find_common_elements(int arr1[], int n1, int arr2[], int n2) {
    printf("Common Elements: ");
    for (int i = 0; i < n1; i++) {
        for (int j = 0; j < n2; j++) {
            if (arr1[i] == arr2[j]) {
                printf("%d ", arr1[i]);
                break;
            }
        }
    }
}

